void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture(sampler_main, vUv).xyz;
    float L = lum(ret);
    float bw = clamp01(cos(L*17 + 3 + vUv.x*30)*30 - 21);
